module top_module(
    input wire clk,
    input wire reset,
    output wire [3:0] count
);reg [3:0] unused_count_reg;

always @(posedge clk) begin
    if (reset) begin
        unused_count_reg <= 4'b0;
    end else begin
        unused_count_reg <= unused_count_reg + 1;
    end
end

assign count = unused_count_reg;

endmodule
